module freq_div(
    input clk,
    input rst_n,
    output clk_50,
    output clk_10,
    output clk_1,
    output clk_50_reg,
    output clk_10_reg,
    output clk_1_reg,
    output clk_10_cnt,
    output clk_1_cnt
);

    reg [1:0] count_50;
    reg [2:0] count_10;
    reg [6:0] count_1;

    always @(posedge CLK_in or posedge RST) begin
        if (RST) begin
            count_50 <= 2'b00;
            count_10 <= 3'b000;
            count_1 <= 7'b0000000;
        end
        else begin
            if (count_50 == 2'b01) begin
                count_50 <= 2'b00;
                CLK_50 <= ~CLK_50;
            end
            else begin
                count_50 <= count_50 + 1'b1;
            end

            if (count_10 == 3'b101) begin
                count_10 <= 3'b000;
                CLK_10 <= ~CLK_10;
            end
            else begin
                count_10 <= count_10 + 1'b1;
            end

            if (count_1 == 7'b1111111) begin
                count_1 <= 7'b0000000;
                CLK_1 <= ~CLK_1;
            end
            else begin
                count_1 <= count_1 + 1'b1;
            end
        end
    end

endmodule
